1	// Package audit provides the centralised audit event logger.
2	// All compliance writes must go through this package.
3	// Direct writes to the audit_events table from other packages are prohibited.
4	package audit
5	
6	import (
7		"context"
8		"encoding/json"
9		"fmt"
10		"log/slog"
11		"math/rand"
12		"time"
13	
14		"lms/internal/domain/audit"
15		"lms/internal/model"
16	)
17	
18	// Logger writes structured audit events via an audit.Repository.
19	// It never panics; if the repository returns an error it is logged with slog
20	// and execution continues. Sensitive values (passwords, tokens, ciphertext)
21	// must never appear in any audit event.
22	type Logger struct {
23		repo audit.Repository
24	}
25	
26	// New creates a new Logger backed by the provided repository.
27	func New(repo audit.Repository) *Logger {
28		return &Logger{repo: repo}
29	}
30	
31	// Log writes a single audit event. If the repository returns an error the
32	// error is logged via slog and the function returns normally — audit failures
33	// must never block business operations.
34	func (l *Logger) Log(ctx context.Context, e *model.AuditEvent) {
35		if e.ID == "" {
36			e.ID = newUUID()
37		}
38		if e.CreatedAt.IsZero() {
39			e.CreatedAt = time.Now().UTC()
40		}
41		if err := l.repo.Insert(ctx, e); err != nil {
42			slog.Error("audit: failed to insert event",
43				"event_type", e.EventType,
44				"actor_user_id", e.ActorUserID,
45				"error", err,
46			)
47		}
48	}
49	
50	// LogLogin records a successful login event.
51	func (l *Logger) LogLogin(ctx context.Context, userID, username, workstationID, ipAddr string) {
52		e := &model.AuditEvent{
53			EventType:     model.AuditLoginSuccess,
54			ActorUserID:   strPtr(userID),
55			ActorUsername: strPtr(username),
56			WorkstationID: strPtr(workstationID),
57			IPAddress:     strPtr(ipAddr),
58		}
59		l.Log(ctx, e)
60	}
61	
62	// LogLoginFailed records a failed login attempt.
63	func (l *Logger) LogLoginFailed(ctx context.Context, username, workstationID, ipAddr, reason string) {
64		// username is logged for audit purposes (not a secret) but no password or
65		// token data is included.
66		e := &model.AuditEvent{
67			EventType:     model.AuditLoginFailure,
68			ActorUsername: strPtr(username),
69			WorkstationID: strPtr(workstationID),
70			IPAddress:     strPtr(ipAddr),
71			Metadata:      map[string]string{"reason": reason},
72		}
73		l.Log(ctx, e)
74	}
75	
76	// LogLockout records an account lockout event.
77	func (l *Logger) LogLockout(ctx context.Context, userID, username string) {
78		e := &model.AuditEvent{
79			EventType:     model.AuditLoginLocked,
80			ActorUserID:   strPtr(userID),
81			ActorUsername: strPtr(username),
82		}
83		l.Log(ctx, e)
84	}
85	
86	// LogLogout records a logout event for the given session.
87	func (l *Logger) LogLogout(ctx context.Context, userID, username, sessionID string) {
88		e := &model.AuditEvent{
89			EventType:     model.AuditLogout,
90			ActorUserID:   strPtr(userID),
91			ActorUsername: strPtr(username),
92			// Session ID is not sensitive (it's an internal UUID, not the token).
93			Metadata: map[string]string{"session_id": sessionID},
94		}
95		l.Log(ctx, e)
96	}
97	
98	// LogAdminChange records an administrative change to a resource.
99	// before and after must NOT contain sensitive field values (passwords,
100	// encrypted ciphertext, session tokens).
101	func (l *Logger) LogAdminChange(ctx context.Context, actorID, actorUsername, resourceType, resourceID string, before, after any) {
102		e := &model.AuditEvent{
103			EventType:     model.AuditUserUpdated,
104			ActorUserID:   strPtr(actorID),
105			ActorUsername: strPtr(actorUsername),
106			ResourceType:  strPtr(resourceType),
107			ResourceID:    strPtr(resourceID),
108			BeforeValue:   sanitize(before),
109			AfterValue:    sanitize(after),
110		}
111		l.Log(ctx, e)
112	}
113	
114	// LogSensitiveReveal records that a staff member revealed a reader's encrypted fields.
115	func (l *Logger) LogSensitiveReveal(ctx context.Context, actorID, actorUsername, readerID string) {
116		e := &model.AuditEvent{
117			EventType:     model.AuditSensitiveRevealed,
118			ActorUserID:   strPtr(actorID),
119			ActorUsername: strPtr(actorUsername),
120			ResourceType:  strPtr("reader"),
121			ResourceID:    strPtr(readerID),
122			// No before/after values — decrypted data must never appear in audit events.
123		}
124		l.Log(ctx, e)
125	}
126	
127	// strPtr returns a pointer to the string, or nil if the string is empty.
128	func strPtr(s string) *string {
129		if s == "" {
130			return nil
131		}
132		return &s
133	}
134	
135	// sanitize converts a value to a JSON-safe representation. It round-trips
136	// through encoding/json so any unexportable fields are stripped. This is a
137	// safety measure — callers should already ensure no sensitive data is passed.
138	func sanitize(v any) any {
139		if v == nil {
140			return nil
141		}
142		b, err := json.Marshal(v)
143		if err != nil {
144			return nil
145		}
146		var out any
147		if err := json.Unmarshal(b, &out); err != nil {
148			return nil
149		}
150		return out
151	}
152	
153	// newUUID generates a random UUID v4 string using math/rand as a fallback.
154	// The audit logger uses the database's uuid_generate_v4() via the INSERT RETURNING id,
155	// so this is only used as a placeholder before the DB assigns the real ID.
156	// In practice, e.ID is set from the DB RETURNING clause after Insert succeeds.
157	func newUUID() string {
158		b := make([]byte, 16)
159		for i := range b {
160			b[i] = byte(rand.Intn(256)) //nolint:gosec // non-security use
161		}
162		b[6] = (b[6] & 0x0f) | 0x40 // version 4
163		b[8] = (b[8] & 0x3f) | 0x80 // variant 10
164		return fmt.Sprintf("%08x-%04x-%04x-%04x-%12x",
165			b[0:4], b[4:6], b[6:8], b[8:10], b[10:16])
166	}
