3	// Pagination carries the offset/limit parameters for list queries.
4	type Pagination struct {
5		Page    int `json:"page"`
6		PerPage int `json:"per_page"`
7	}
8	
9	// Offset returns the SQL OFFSET for this page.
10	func (p Pagination) Offset() int {
11		if p.Page < 1 {
12			p.Page = 1
13		}
14		return (p.Page - 1) * p.PerPage
15	}
16	
17	// Limit returns the SQL LIMIT, clamped to a maximum of 200.
18	func (p Pagination) Limit() int {
19		if p.PerPage < 1 {
20			return 20
21		}
22		if p.PerPage > 200 {
23			return 200
24		}
25		return p.PerPage
26	}
27	
28	// DefaultPagination returns a Pagination with sensible defaults.
29	func DefaultPagination() Pagination {
30		return Pagination{Page: 1, PerPage: 20}
31	}
32	
33	// PageResult wraps a list result with total-count metadata.
34	type PageResult[T any] struct {
35		Items      []T `json:"items"`
36		Total      int `json:"total"`
37		Page       int `json:"page"`
38		PerPage    int `json:"per_page"`
39		TotalPages int `json:"total_pages"`
40	}
41	
42	// NewPageResult constructs a PageResult from items, total count, and pagination params.
43	func NewPageResult[T any](items []T, total int, p Pagination) PageResult[T] {
44		totalPages := 1
45		if p.Limit() > 0 && total > 0 {
46			totalPages = (total + p.Limit() - 1) / p.Limit()
47		}
48		return PageResult[T]{
49			Items:      items,
50			Total:      total,
51			Page:       p.Page,
52			PerPage:    p.Limit(),
53			TotalPages: totalPages,
54		}
55	}
