1	// Package apperr defines application-level error types used across all domain
2	// packages. Each type maps to a specific HTTP status code in the error handler
3	// middleware. Using typed errors (not string matching) keeps the boundary clean.
4	package apperr
5	
6	import "fmt"
7	
8	// NotFound is returned when a resource cannot be found, including when branch
9	// scoping hides it from the caller. Do not distinguish "not found" from
10	// "found but access denied" in responses — return 404 for both to prevent
11	// enumeration attacks.
12	type NotFound struct {
13		Resource string
14		ID       string
15	}
16	
17	func (e *NotFound) Error() string {
18		if e.ID != "" {
19			return fmt.Sprintf("%s not found: %s", e.Resource, e.ID)
20		}
21		return fmt.Sprintf("%s not found", e.Resource)
22	}
23	
24	// Validation is returned when input fails business-rule or format validation.
25	// Field may be empty for entity-level (cross-field) errors.
26	type Validation struct {
27		Field   string
28		Message string
29	}
30	
31	func (e *Validation) Error() string {
32		if e.Field != "" {
33			return fmt.Sprintf("validation error — %s: %s", e.Field, e.Message)
34		}
35		return fmt.Sprintf("validation error: %s", e.Message)
36	}
37	
38	// Conflict is returned for uniqueness violations or state machine violations
39	// (e.g. enrolling in a full program, duplicate barcode).
40	type Conflict struct {
41		Resource string
42		Message  string
43	}
44	
45	func (e *Conflict) Error() string {
46		return fmt.Sprintf("conflict on %s: %s", e.Resource, e.Message)
47	}
48	
49	// Forbidden is returned when the caller is authenticated but lacks permission
50	// for the requested action. Do not include the reason for the denial.
51	type Forbidden struct {
52		Action   string
53		Resource string
54	}
55	
56	func (e *Forbidden) Error() string {
57		return fmt.Sprintf("forbidden: %s %s", e.Action, e.Resource)
58	}
59	
60	// Unauthorized is returned when the caller is not authenticated (no valid session).
61	type Unauthorized struct{}
62	
63	func (e *Unauthorized) Error() string {
64		return "authentication required"
65	}
66	
67	// AccountLocked is returned when a user account is locked due to failed attempts.
68	type AccountLocked struct {
69		SecondsRemaining int
70	}
71	
72	func (e *AccountLocked) Error() string {
73		return fmt.Sprintf("account locked for %d more seconds", e.SecondsRemaining)
74	}
75	
76	// CaptchaRequired is returned when a CAPTCHA challenge must be solved before retrying.
77	type CaptchaRequired struct {
78		ChallengeKey string
79	}
80	
81	func (e *CaptchaRequired) Error() string {
82		return "CAPTCHA required before next login attempt"
83	}
84	
85	// Internal is returned for unexpected server-side failures. The detail is
86	// logged server-side but a generic message is returned to the client.
87	type Internal struct {
88		Cause error
89	}
90	
91	func (e *Internal) Error() string {
92		return "an internal error occurred"
93	}
94	
95	func (e *Internal) Unwrap() error {
96		return e.Cause
97	}
98	
99	// Unimplemented is returned by scaffold handlers that are not yet implemented.
100	type Unimplemented struct {
101		Feature string
102	}
103	
104	func (e *Unimplemented) Error() string {
105		return fmt.Sprintf("%s is not yet implemented", e.Feature)
106	}
107	

