1	package users
2	
3	import (
4		"net/http"
5		"time"
6	
7		"github.com/labstack/echo/v4"
8	
9		"lms/internal/apperr"
10		"lms/internal/ctxutil"
11		"lms/internal/model"
12	)
13	
14	const (
15		sessionCookieName = "lms_session"
16		sessionCookiePath = "/"
17	)
18	
19	// Handler holds the HTTP handlers for authentication routes.
20	type Handler struct {
21		service *Service
22	}
23	
24	// NewHandler creates a new auth Handler.
25	func NewHandler(service *Service) *Handler {
26		return &Handler{service: service}
27	}
28	
29	// RegisterRoutes registers authentication routes on the given Echo group.
30	// The group is expected to be the /api/v1 group.
31	func (h *Handler) RegisterRoutes(api *echo.Group, authMW ...echo.MiddlewareFunc) {
32		auth := api.Group("/auth")
33		auth.POST("/login", h.Login)
34	
35		// Protected routes require an active session.
36		if len(authMW) > 0 {
37			auth.GET("/me", h.Me, authMW...)
38			auth.POST("/logout", h.Logout, authMW...)
39			auth.POST("/stepup", h.StepUp, authMW...)
40		} else {
41			auth.GET("/me", h.Me)
42			auth.POST("/logout", h.Logout)
43			auth.POST("/stepup", h.StepUp)
44		}
45	}
46	
47	// loginRequest is the JSON body for POST /api/v1/auth/login.
48	type loginRequest struct {
49		Username      string `json:"username"`
50		Password      string `json:"password"`
51		CaptchaKey    string `json:"captcha_key"`
52		CaptchaAnswer string `json:"captcha_answer"`
53	}
54	
55	// loginResponse is the JSON body returned on successful login.
56	type loginResponse struct {
57		User            *model.UserWithRoles `json:"user"`
58		CaptchaRequired bool                 `json:"captcha_required"`
59	}
60	
61	// Login handles POST /api/v1/auth/login.
62	// On success, sets an httpOnly session cookie and returns 200 with the user object.
63	// Sensitive data (password_hash) is never serialised via model tags (json:"-").
64	func (h *Handler) Login(c echo.Context) error {
65		var req loginRequest
66		if err := c.Bind(&req); err != nil {
67			return &apperr.Validation{Field: "body", Message: "invalid JSON"}
68		}
69		if req.Username == "" || req.Password == "" {
70			return &apperr.Validation{Field: "username", Message: "username and password are required"}
71		}
72	
73		workstationID := ctxutil.GetWorkstationID(c)
74		ipAddr := ctxutil.GetIPAddress(c)
75	
76		result, err := h.service.Login(
77			c.Request().Context(),
78			req.Username, req.Password,
79			req.CaptchaKey, req.CaptchaAnswer,
80			workstationID, ipAddr,
81		)
82		if err != nil {
83			return err
84		}
85	
86		// Set the session cookie — httpOnly, SameSite=Strict, no Secure flag
87		// (offline-first deployment with no TLS assumed at this stage).
88		cookie := &http.Cookie{
89			Name:     sessionCookieName,
90			Value:    result.SessionToken,
91			Path:     sessionCookiePath,
92			HttpOnly: true,
93			SameSite: http.SameSiteStrictMode,
94			Secure:   false,
95			MaxAge:   0, // session cookie — expires when browser closes
96			Expires:  result.Session.ExpiresAt,
97		}
98		c.SetCookie(cookie)
99	
100		return c.JSON(http.StatusOK, loginResponse{
101			User:            result.User,
102			CaptchaRequired: false,
103		})
104	}
105	
106	// Logout handles POST /api/v1/auth/logout.
107	// Invalidates the session and clears the cookie. Returns 204 No Content.
108	func (h *Handler) Logout(c echo.Context) error {
109		ctx := c.Request().Context()
110		session, ok := ctxutil.GetSession(ctx)
111		if !ok || session == nil {
112			return &apperr.Unauthorized{}
113		}
114		user, _ := ctxutil.GetUser(ctx)
115	
116		var userID, username string
117		if user != nil && user.User != nil {
118			userID = user.User.ID
119			username = user.User.Username
120		}
121	
122		workstationID := ctxutil.GetWorkstationID(c)
123		if err := h.service.Logout(ctx, session.ID, userID, username, workstationID); err != nil {
124			return err
125		}
126	
127		// Clear the session cookie by expiring it immediately.
128		c.SetCookie(&http.Cookie{
129			Name:     sessionCookieName,
130			Value:    "",
131			Path:     sessionCookiePath,
132			HttpOnly: true,
133			SameSite: http.SameSiteStrictMode,
134			Secure:   false,
135			MaxAge:   -1,
136			Expires:  time.Unix(0, 0),
137		})
138	
139		return c.NoContent(http.StatusNoContent)
140	}
141	
142	// stepUpRequest is the JSON body for POST /api/v1/auth/stepup.
143	type stepUpRequest struct {
144		Password string `json:"password"`
145	}
146	
147	// Me handles GET /api/v1/auth/me.
148	// Returns the currently authenticated user with their roles and permissions.
149	// Used by the frontend to restore session state on page load.
150	func (h *Handler) Me(c echo.Context) error {
151		user, ok := ctxutil.GetUser(c.Request().Context())
152		if !ok || user == nil {
153			return &apperr.Unauthorized{}
154		}
155		// Return UserWithRoles directly — serialises as { user: {...}, roles: [...], permissions: [...] }.
156		return c.JSON(http.StatusOK, user)
157	}
158	
159	// StepUp handles POST /api/v1/auth/stepup.
160	// Verifies the user's current password without creating a new session.
161	// Returns 200 {ok: true} on success, 401 on failure.
162	func (h *Handler) StepUp(c echo.Context) error {
163		var req stepUpRequest
164		if err := c.Bind(&req); err != nil {
165			return &apperr.Validation{Field: "body", Message: "invalid JSON"}
166		}
167		if req.Password == "" {
168			return &apperr.Validation{Field: "password", Message: "password is required"}
169		}
170	
171		user, ok := ctxutil.GetUser(c.Request().Context())
172		if !ok || user == nil {
173			return &apperr.Unauthorized{}
174		}
175	
176		if err := h.service.StepUp(c.Request().Context(), user.User.ID, req.Password); err != nil {
177			return err
178		}
179	
180		return c.JSON(http.StatusOK, map[string]bool{"ok": true})
181	}
