1	// DataTable is a reusable table shell for domain list views.
2	//
3	// Features:
4	//   - Typed column definitions with custom cell renderers
5	//   - Optional sort indicators (sort control is caller-managed)
6	//   - Loading, error, and empty states via inline slot components
7	//   - Row click handler for detail navigation
8	//   - Workstation-dense layout (compact rows, monospace identifiers)
9	//
10	// Usage:
11	//   <DataTable
12	//     columns={[
13	//       { key: 'reader_number', header: 'Reader #', render: r => r.reader_number },
14	//       { key: 'name',          header: 'Name',     render: r => `${r.first_name} ${r.last_name}` },
15	//     ]}
16	//     rows={readers}
17	//     rowKey={r => r.id}
18	//     loading={isLoading}
19	//     onRowClick={r => navigate(`/readers/${r.id}`)}
20	//   />
21	
22	import LoadingState from './LoadingState';
23	import ErrorState from './ErrorState';
24	import EmptyState from './EmptyState';
25	
26	export interface Column<T> {
27	  key: string;
28	  header: string;
29	  render: (row: T, index: number) => React.ReactNode;
30	  /** Hint for column width (e.g. '120px', '1fr'). Default: auto. */
31	  width?: string;
32	  /** Whether the header shows a sort indicator. Actual sort is caller-managed. */
33	  sortable?: boolean;
34	  sortDirection?: 'asc' | 'desc' | 'none';
35	  onSort?: () => void;
36	  align?: 'left' | 'right' | 'center';
37	}
38	
39	interface DataTableProps<T> {
40	  columns: Column<T>[];
41	  rows: T[];
42	  rowKey: (row: T) => string;
43	  loading?: boolean;
44	  error?: string;
45	  onRetry?: () => void;
46	  onRowClick?: (row: T) => void;
47	  emptyMessage?: string;
48	  emptyDetail?: string;
49	  /** Label for an optional empty-state action button. */
50	  emptyActionLabel?: string;
51	  onEmptyAction?: () => void;
52	  caption?: string;
53	}
54	
55	const TH_STYLE: React.CSSProperties = {
56	  padding: '0.5rem 0.75rem',
57	  textAlign: 'left',
58	  fontWeight: 600,
59	  fontSize: '0.75rem',
60	  color: '#6b7280',
61	  borderBottom: '2px solid #e5e7eb',
62	  background: '#f9fafb',
63	  whiteSpace: 'nowrap',
64	  userSelect: 'none',
65	};
66	
67	const TD_STYLE: React.CSSProperties = {
68	  padding: '0.5rem 0.75rem',
69	  fontSize: '0.8125rem',
70	  color: '#1a1a2e',
71	  borderBottom: '1px solid #f3f4f6',
72	  verticalAlign: 'middle',
73	};
74	
75	export default function DataTable<T>({
76	  columns,
77	  rows,
78	  rowKey,
79	  loading = false,
80	  error,
81	  onRetry,
82	  onRowClick,
83	  emptyMessage,
84	  emptyDetail,
85	  emptyActionLabel,
86	  onEmptyAction,
87	  caption,
88	}: DataTableProps<T>) {
89	  if (loading) return <LoadingState />;
90	  if (error) return <ErrorState message={error} onRetry={onRetry} />;
91	
92	  return (
93	    <div
94	      style={{
95	        background: '#fff',
96	        border: '1px solid #e5e7eb',
97	        borderRadius: '6px',
98	        overflow: 'hidden',
99	      }}
100	    >
101	      <div style={{ overflowX: 'auto' }}>
102	        <table
103	          style={{ width: '100%', borderCollapse: 'collapse', minWidth: '400px' }}
104	          aria-label={caption}
105	        >
106	          {caption && <caption style={{ display: 'none' }}>{caption}</caption>}
107	          <thead>
108	            <tr>
109	              {columns.map((col) => (
110	                <th
111	                  key={col.key}
112	                  style={{
113	                    ...TH_STYLE,
114	                    width: col.width,
115	                    textAlign: col.align ?? 'left',
116	                    cursor: col.sortable ? 'pointer' : undefined,
117	                  }}
118	                  onClick={col.sortable ? col.onSort : undefined}
119	                  aria-sort={
120	                    col.sortDirection === 'asc'
121	                      ? 'ascending'
122	                      : col.sortDirection === 'desc'
123	                        ? 'descending'
124	                        : undefined
125	                  }
126	                >
127	                  {col.header}
128	                  {col.sortable && col.sortDirection === 'asc' && ' ▲'}
129	                  {col.sortable && col.sortDirection === 'desc' && ' ▼'}
130	                </th>
131	              ))}
132	            </tr>
133	          </thead>
134	          <tbody>
135	            {rows.length === 0 ? (
136	              <tr>
137	                <td colSpan={columns.length} style={{ padding: 0 }}>
138	                  <EmptyState
139	                    message={emptyMessage ?? 'No records found'}
140	                    detail={emptyDetail}
141	                    actionLabel={emptyActionLabel}
142	                    onAction={onEmptyAction}
143	                  />
144	                </td>
145	              </tr>
146	            ) : (
147	              rows.map((row, i) => (
148	                <tr
149	                  key={rowKey(row)}
150	                  onClick={onRowClick ? () => onRowClick(row) : undefined}
151	                  style={{
152	                    cursor: onRowClick ? 'pointer' : undefined,
153	                    background: i % 2 === 0 ? '#fff' : '#fafafa',
154	                  }}
155	                  onMouseEnter={(e) => {
156	                    if (onRowClick) (e.currentTarget as HTMLTableRowElement).style.background = '#eff6ff';
157	                  }}
158	                  onMouseLeave={(e) => {
159	                    if (onRowClick) (e.currentTarget as HTMLTableRowElement).style.background = i % 2 === 0 ? '#fff' : '#fafafa';
160	                  }}
161	                >
162	                  {columns.map((col) => (
163	                    <td
164	                      key={col.key}
165	                      style={{ ...TD_STYLE, textAlign: col.align ?? 'left' }}
166	                    >
167	                      {col.render(row, i)}
168	                    </td>
169	                  ))}
170	                </tr>
171	              ))
172	            )}
173	          </tbody>
174	        </table>
175	      </div>
176	    </div>
177	  );
178	}
