1	// StepUpModal requires the user to re-enter their password before a sensitive
2	// action is performed (e.g. revealing encrypted reader fields).
3	//
4	// The step-up check is always server-validated via POST /api/v1/auth/stepup.
5	// The client never decides whether the password is correct — the server does.
6	//
7	// Usage:
8	//   <StepUpModal
9	//     title="Reveal sensitive field"
10	//     description="Enter your password to view this field."
11	//     onSuccess={() => setRevealed(true)}
12	//     onCancel={() => setShowModal(false)}
13	//   />
14	
15	import { FormEvent, useState } from 'react';
16	import { apiClient, HttpError } from '../api/client';
17	
18	interface StepUpModalProps {
19	  title?: string;
20	  description?: string;
21	  onSuccess: () => void;
22	  onCancel: () => void;
23	}
24	
25	export default function StepUpModal({
26	  title = 'Confirm your identity',
27	  description = 'Enter your password to continue.',
28	  onSuccess,
29	  onCancel,
30	}: StepUpModalProps) {
31	  const [password, setPassword] = useState('');
32	  const [error, setError] = useState<string | null>(null);
33	  const [submitting, setSubmitting] = useState(false);
34	
35	  async function handleSubmit(e: FormEvent) {
36	    e.preventDefault();
37	    setError(null);
38	    setSubmitting(true);
39	
40	    try {
41	      await apiClient.post<{ ok: boolean }>('/auth/stepup', { password });
42	      // Server validated the password — call the success handler.
43	      onSuccess();
44	    } catch (err) {
45	      if (err instanceof HttpError && err.status === 401) {
46	        setError('Incorrect password. Please try again.');
47	      } else if (err instanceof HttpError && err.status === 422) {
48	        setError(err.body.detail ?? 'Password is required.');
49	      } else {
50	        setError('Could not verify your identity. Please try again.');
51	      }
52	    } finally {
53	      setSubmitting(false);
54	    }
55	  }
56	
57	  return (
58	    // Backdrop
59	    <div
60	      role="dialog"
61	      aria-modal="true"
62	      aria-labelledby="stepup-title"
63	      style={{
64	        position: 'fixed',
65	        inset: 0,
66	        background: 'rgba(0,0,0,0.4)',
67	        display: 'flex',
68	        alignItems: 'center',
69	        justifyContent: 'center',
70	        zIndex: 10000,
71	        fontFamily: 'system-ui, -apple-system, sans-serif',
72	      }}
73	      onClick={(e) => {
74	        if (e.target === e.currentTarget) onCancel();
75	      }}
76	    >
77	      {/* Dialog box */}
78	      <div
79	        style={{
80	          background: '#fff',
81	          borderRadius: '6px',
82	          padding: '1.5rem',
83	          width: '100%',
84	          maxWidth: '380px',
85	          boxShadow: '0 8px 32px rgba(0,0,0,0.18)',
86	        }}
87	      >
88	        <div
89	          id="stepup-title"
90	          style={{ fontWeight: 700, fontSize: '1rem', marginBottom: '0.375rem', color: '#1a1a2e' }}
91	        >
92	          {title}
93	        </div>
94	        <div style={{ fontSize: '0.8125rem', color: '#6b7280', marginBottom: '1.25rem' }}>
95	          {description}
96	        </div>
97	
98	        {error && (
99	          <div
100	            role="alert"
101	            style={{
102	              background: '#fef2f2',
103	              border: '1px solid #fca5a5',
104	              borderRadius: '4px',
105	              padding: '0.625rem 0.875rem',
106	              fontSize: '0.8125rem',
107	              color: '#dc2626',
108	              marginBottom: '1rem',
109	            }}
110	          >
111	            {error}
112	          </div>
113	        )}
114	
115	        <form onSubmit={handleSubmit}>
116	          <label
117	            htmlFor="stepup-password"
118	            style={{ display: 'block', fontSize: '0.8125rem', fontWeight: 500, marginBottom: '0.375rem', color: '#374151' }}
119	          >
120	            Password
121	          </label>
122	          <input
123	            id="stepup-password"
124	            type="password"
125	            autoComplete="current-password"
126	            autoFocus
127	            required
128	            value={password}
129	            onChange={(e) => setPassword(e.target.value)}
130	            disabled={submitting}
131	            style={{
132	              display: 'block',
133	              width: '100%',
134	              padding: '0.5rem 0.75rem',
135	              border: '1px solid #d1d5db',
136	              borderRadius: '4px',
137	              fontSize: '0.875rem',
138	              marginBottom: '1.25rem',
139	              boxSizing: 'border-box',
140	              color: '#1a1a2e',
141	            }}
142	          />
143	
144	          <div style={{ display: 'flex', gap: '0.625rem', justifyContent: 'flex-end' }}>
145	            <button
146	              type="button"
147	              onClick={onCancel}
148	              style={{
149	                padding: '0.5rem 1rem',
150	                background: '#fff',
151	                color: '#374151',
152	                border: '1px solid #d1d5db',
153	                borderRadius: '4px',
154	                cursor: 'pointer',
155	                fontSize: '0.875rem',
156	              }}
157	            >
158	              Cancel
159	            </button>
160	            <button
161	              type="submit"
162	              disabled={submitting || password.length === 0}
163	              style={{
164	                padding: '0.5rem 1rem',
165	                background: '#2563eb',
166	                color: '#fff',
167	                border: 'none',
168	                borderRadius: '4px',
169	                cursor: submitting ? 'not-allowed' : 'pointer',
170	                fontSize: '0.875rem',
171	                fontWeight: 600,
172	                opacity: submitting ? 0.7 : 1,
173	              }}
174	            >
175	              {submitting ? 'Verifying…' : 'Confirm'}
176	            </button>
177	          </div>
178	        </form>
179	      </div>
180	    </div>
181	  );
182	}
