1	// MaskedField displays a privacy-sensitive value.
2	//
3	// Default state: shows "••••••" (matching the server's masking convention).
4	// Reveal state: shows the decrypted value after a successful step-up check.
5	//
6	// The "Reveal" button is only rendered if `canReveal` is true (caller checks
7	// the user's permission, e.g. "readers:reveal_sensitive"). This ensures the
8	// button is not rendered in a hidden-but-clickable way for unauthorized users.
9	//
10	// The reveal flow calls POST /api/v1/readers/:id/reveal, which:
11	//   1. Validates the step-up password server-side
12	//   2. Returns decrypted values (or 501 until Phase 6)
13	//
14	// Until Phase 6 (reader domain), the reveal returns 501. The component handles
15	// this gracefully with a "Not yet available" message.
16	
17	import { useState } from 'react';
18	import StepUpModal from './StepUpModal';
19	import { apiClient, HttpError } from '../api/client';
20	
21	interface MaskedFieldProps {
22	  label: string;
23	  fieldKey: string;
24	  /** The resource ID used in the reveal API call (e.g. reader ID). */
25	  resourceId: string;
26	  /** Endpoint prefix for reveal, e.g. '/readers'. Produces /:id/reveal. */
27	  revealEndpoint: string;
28	  /** Whether the current user has permission to reveal this field. */
29	  canReveal: boolean;
30	}
31	
32	const MASK = '••••••';
33	
34	export default function MaskedField({
35	  label,
36	  fieldKey,
37	  resourceId,
38	  revealEndpoint,
39	  canReveal,
40	}: MaskedFieldProps) {
41	  const [showModal, setShowModal] = useState(false);
42	  const [revealedValue, setRevealedValue] = useState<string | null>(null);
43	  const [revealError, setRevealError] = useState<string | null>(null);
44	  const [revealing, setRevealing] = useState(false);
45	
46	  async function handleStepUpSuccess() {
47	    setShowModal(false);
48	    setRevealError(null);
49	    setRevealing(true);
50	
51	    try {
52	      // The reveal endpoint validates the step-up and returns decrypted fields.
53	      // POST /api/v1{revealEndpoint}/:id/reveal
54	      const res = await apiClient.post<Record<string, string>>(
55	        `${revealEndpoint}/${resourceId}/reveal`,
56	        {},  // password was already submitted to /auth/stepup by StepUpModal
57	      );
58	      const value = res[fieldKey];
59	      setRevealedValue(value ?? '(empty)');
60	    } catch (err) {
61	      if (err instanceof HttpError && err.status === 501) {
62	        setRevealError('Field decryption not yet available (Phase 6).');
63	      } else if (err instanceof HttpError && err.status === 401) {
64	        setRevealError('Step-up session expired. Please try again.');
65	      } else {
66	        setRevealError('Could not retrieve field value.');
67	      }
68	    } finally {
69	      setRevealing(false);
70	    }
71	  }
72	
73	  return (
74	    <div
75	      style={{
76	        display: 'flex',
77	        alignItems: 'center',
78	        gap: '0.625rem',
79	        padding: '0.375rem 0',
80	        fontFamily: 'system-ui, -apple-system, sans-serif',
81	      }}
82	    >
83	      <span
84	        style={{
85	          fontSize: '0.75rem',
86	          fontWeight: 600,
87	          color: '#6b7280',
88	          minWidth: '120px',
89	          textTransform: 'uppercase',
90	          letterSpacing: '0.04em',
91	        }}
92	      >
93	        {label}
94	      </span>
95	
96	      <span
97	        data-testid={`masked-field-${fieldKey}`}
98	        style={{
99	          fontFamily: revealedValue ? 'inherit' : 'monospace',
100	          fontSize: '0.875rem',
101	          color: revealedValue ? '#1a1a2e' : '#9ca3af',
102	          letterSpacing: revealedValue ? undefined : '0.15em',
103	          minWidth: '80px',
104	        }}
105	      >
106	        {revealing ? '…' : (revealedValue ?? MASK)}
107	      </span>
108	
109	      {revealError && (
110	        <span style={{ fontSize: '0.75rem', color: '#dc2626' }}>{revealError}</span>
111	      )}
112	
113	      {/* Only render the reveal button if the user has permission */}
114	      {canReveal && !revealedValue && !revealing && !revealError && (
115	        <button
116	          onClick={() => setShowModal(true)}
117	          aria-label={`Reveal ${label}`}
118	          style={{
119	            padding: '0.1875rem 0.625rem',
120	            background: '#eff6ff',
121	            color: '#2563eb',
122	            border: '1px solid #bfdbfe',
123	            borderRadius: '4px',
124	            cursor: 'pointer',
125	            fontSize: '0.6875rem',
126	            fontWeight: 600,
127	          }}
128	        >
129	          Reveal
130	        </button>
131	      )}
132	
133	      {revealedValue && (
134	        <button
135	          onClick={() => { setRevealedValue(null); setRevealError(null); }}
136	          aria-label={`Hide ${label}`}
137	          style={{
138	            padding: '0.1875rem 0.625rem',
139	            background: '#f3f4f6',
140	            color: '#6b7280',
141	            border: '1px solid #e5e7eb',
142	            borderRadius: '4px',
143	            cursor: 'pointer',
144	            fontSize: '0.6875rem',
145	          }}
146	        >
147	          Hide
148	        </button>
149	      )}
150	
151	      {showModal && (
152	        <StepUpModal
153	          title={`Reveal ${label}`}
154	          description={`Enter your password to view the ${label.toLowerCase()} for this record.`}
155	          onSuccess={handleStepUpSuccess}
156	          onCancel={() => setShowModal(false)}
157	        />
158	      )}
159	    </div>
160	  );
161	}
