1	// FilterBar is a horizontal row of filter inputs for list/search views.
2	//
3	// Design: all filter state lives in the caller. FilterBar calls onChange on each
4	// input change and onApply/onClear on explicit user action. This keeps the
5	// component stateless and testable.
6	//
7	// Usage:
8	//   const [filters, setFilters] = useState({ status: '', search: '' });
9	//
10	//   <FilterBar
11	//     fields={[
12	//       { name: 'search', label: 'Search', type: 'text', placeholder: 'Name or reader #' },
13	//       { name: 'status', label: 'Status', type: 'select',
14	//         options: [{ value: 'active', label: 'Active' }, { value: 'frozen', label: 'Frozen' }] },
15	//     ]}
16	//     values={filters}
17	//     onChange={(name, value) => setFilters(f => ({ ...f, [name]: value }))}
18	//     onApply={() => refetch()}
19	//     onClear={() => { setFilters({ status: '', search: '' }); refetch(); }}
20	//   />
21	
22	export interface FilterFieldDef {
23	  name: string;
24	  label: string;
25	  type: 'text' | 'select' | 'date';
26	  placeholder?: string;
27	  options?: { value: string; label: string }[];
28	}
29	
30	interface FilterBarProps {
31	  fields: FilterFieldDef[];
32	  values: Record<string, string>;
33	  onChange: (name: string, value: string) => void;
34	  onApply: () => void;
35	  onClear: () => void;
36	  /** Whether a fetch is in progress (disables Apply button). */
37	  loading?: boolean;
38	}
39	
40	const INPUT_STYLE: React.CSSProperties = {
41	  padding: '0.375rem 0.625rem',
42	  border: '1px solid #d1d5db',
43	  borderRadius: '4px',
44	  fontSize: '0.8125rem',
45	  background: '#fff',
46	  color: '#1a1a2e',
47	  minWidth: '140px',
48	};
49	
50	export default function FilterBar({
51	  fields,
52	  values,
53	  onChange,
54	  onApply,
55	  onClear,
56	  loading = false,
57	}: FilterBarProps) {
58	  function handleKeyDown(e: React.KeyboardEvent) {
59	    if (e.key === 'Enter') onApply();
60	  }
61	
62	  return (
63	    <div
64	      style={{
65	        display: 'flex',
66	        flexWrap: 'wrap',
67	        alignItems: 'flex-end',
68	        gap: '0.75rem',
69	        padding: '0.875rem 1rem',
70	        background: '#f9fafb',
71	        border: '1px solid #e5e7eb',
72	        borderRadius: '6px',
73	        marginBottom: '1rem',
74	      }}
75	    >
76	      {fields.map((field) => (
77	        <div key={field.name} style={{ display: 'flex', flexDirection: 'column', gap: '0.25rem' }}>
78	          <label
79	            htmlFor={`filter-${field.name}`}
80	            style={{ fontSize: '0.6875rem', fontWeight: 600, color: '#6b7280', textTransform: 'uppercase', letterSpacing: '0.06em' }}
81	          >
82	            {field.label}
83	          </label>
84	
85	          {field.type === 'select' ? (
86	            <select
87	              id={`filter-${field.name}`}
88	              value={values[field.name] ?? ''}
89	              onChange={(e) => onChange(field.name, e.target.value)}
90	              style={INPUT_STYLE}
91	            >
92	              <option value="">All</option>
93	              {field.options?.map((opt) => (
94	                <option key={opt.value} value={opt.value}>
95	                  {opt.label}
96	                </option>
97	              ))}
98	            </select>
99	          ) : (
100	            <input
101	              id={`filter-${field.name}`}
102	              type={field.type}
103	              value={values[field.name] ?? ''}
104	              placeholder={field.placeholder}
105	              onChange={(e) => onChange(field.name, e.target.value)}
106	              onKeyDown={handleKeyDown}
107	              style={INPUT_STYLE}
108	            />
109	          )}
110	        </div>
111	      ))}
112	
113	      <div style={{ display: 'flex', gap: '0.5rem', alignItems: 'flex-end' }}>
114	        <button
115	          onClick={onApply}
116	          disabled={loading}
117	          style={{
118	            padding: '0.375rem 0.875rem',
119	            background: '#2563eb',
120	            color: '#fff',
121	            border: 'none',
122	            borderRadius: '4px',
123	            cursor: loading ? 'not-allowed' : 'pointer',
124	            fontSize: '0.8125rem',
125	            fontWeight: 600,
126	            opacity: loading ? 0.7 : 1,
127	          }}
128	        >
129	          {loading ? 'Loading…' : 'Apply'}
130	        </button>
131	        <button
132	          onClick={onClear}
133	          style={{
134	            padding: '0.375rem 0.875rem',
135	            background: '#fff',
136	            color: '#374151',
137	            border: '1px solid #d1d5db',
138	            borderRadius: '4px',
139	            cursor: 'pointer',
140	            fontSize: '0.8125rem',
141	          }}
142	        >
143	          Clear
144	        </button>
145	      </div>
146	    </div>
147	  );
148	}
149	

