1	// Pagination controls for list views.
2	// All state lives in the caller — this component fires callbacks only.
3	
4	interface PaginationProps {
5	  page: number;
6	  totalPages: number;
7	  pageSize: number;
8	  totalItems: number;
9	  onPageChange: (page: number) => void;
10	  onPageSizeChange?: (size: number) => void;
11	  pageSizeOptions?: number[];
12	}
13	
14	const BTN: React.CSSProperties = {
15	  padding: '0.3125rem 0.625rem',
16	  border: '1px solid #d1d5db',
17	  background: '#fff',
18	  color: '#374151',
19	  borderRadius: '4px',
20	  cursor: 'pointer',
21	  fontSize: '0.8125rem',
22	};
23	
24	const BTN_DISABLED: React.CSSProperties = {
25	  ...BTN,
26	  opacity: 0.4,
27	  cursor: 'not-allowed',
28	};
29	
30	export default function Pagination({
31	  page,
32	  totalPages,
33	  pageSize,
34	  totalItems,
35	  onPageChange,
36	  onPageSizeChange,
37	  pageSizeOptions = [20, 50, 100],
38	}: PaginationProps) {
39	  const start = totalItems === 0 ? 0 : (page - 1) * pageSize + 1;
40	  const end = Math.min(page * pageSize, totalItems);
41	
42	  return (
43	    <div
44	      style={{
45	        display: 'flex',
46	        alignItems: 'center',
47	        justifyContent: 'space-between',
48	        padding: '0.625rem 0',
49	        fontSize: '0.8125rem',
50	        color: '#6b7280',
51	        flexWrap: 'wrap',
52	        gap: '0.5rem',
53	      }}
54	    >
55	      <span>
56	        {totalItems === 0
57	          ? 'No results'
58	          : `${start}–${end} of ${totalItems.toLocaleString()}`}
59	      </span>
60	
61	      <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
62	        {onPageSizeChange && (
63	          <label style={{ display: 'flex', alignItems: 'center', gap: '0.375rem' }}>
64	            Rows:
65	            <select
66	              value={pageSize}
67	              onChange={(e) => onPageSizeChange(Number(e.target.value))}
68	              style={{ padding: '0.25rem', border: '1px solid #d1d5db', borderRadius: '4px', fontSize: '0.8125rem' }}
69	            >
70	              {pageSizeOptions.map((n) => (
71	                <option key={n} value={n}>{n}</option>
72	              ))}
73	            </select>
74	          </label>
75	        )}
76	
77	        <button
78	          style={page <= 1 ? BTN_DISABLED : BTN}
79	          disabled={page <= 1}
80	          onClick={() => onPageChange(page - 1)}
81	          aria-label="Previous page"
82	        >
83	          ‹ Prev
84	        </button>
85	
86	        <span style={{ padding: '0 0.25rem' }}>
87	          {page} / {totalPages || 1}
88	        </span>
89	
90	        <button
91	          style={page >= totalPages ? BTN_DISABLED : BTN}
92	          disabled={page >= totalPages}
93	          onClick={() => onPageChange(page + 1)}
94	          aria-label="Next page"
95	        >
96	          Next ›
97	        </button>
98	      </div>
99	    </div>
100	  );
101	}
102	

