1	// API client for the LMS backend.
2	// Uses fetch with credentials: 'include' so the session cookie is sent on every request.
3	// Throws HttpError for non-2xx responses — callers handle specific status codes.
4	//
5	// 401 interception: any 401 from a domain call triggers the registered handler
6	// (set by AuthContext on mount) so the user is redirected to login automatically.
7	
8	export interface ApiErrorBody {
9	  error: string;
10	  detail?: string;
11	  field?: string;
12	  retry_after_seconds?: number;
13	  challenge_key?: string;
14	  challenge?: string;
15	}
16	
17	export class HttpError extends Error {
18	  constructor(
19	    public readonly status: number,
20	    public readonly body: ApiErrorBody,
21	  ) {
22	    super(`HTTP ${status}: ${body.error}`);
23	    this.name = 'HttpError';
24	  }
25	}
26	
27	// ── Global 401 handler ────────────────────────────────────────────────────────
28	// AuthContext registers this callback on mount. When any authenticated API call
29	// returns 401, the handler clears auth state and triggers a login redirect.
30	// The initial /auth/me call on page load is expected to return 401 when not
31	// logged in; the handler is safe because AuthContext only acts if already authed.
32	
33	let _onUnauthorized: (() => void) | null = null;
34	
35	export function setUnauthorizedHandler(fn: () => void): void {
36	  _onUnauthorized = fn;
37	}
38	
39	export function clearUnauthorizedHandler(): void {
40	  _onUnauthorized = null;
41	}
42	
43	// ── Core request ──────────────────────────────────────────────────────────────
44	
45	async function request<T>(method: string, path: string, body?: unknown): Promise<T> {
46	  const options: RequestInit = {
47	    method,
48	    credentials: 'include',
49	    headers: {
50	      'Content-Type': 'application/json',
51	      Accept: 'application/json',
52	    },
53	  };
54	
55	  if (body !== undefined) {
56	    options.body = JSON.stringify(body);
57	  }
58	
59	  const res = await fetch(`/api/v1${path}`, options);
60	
61	  if (res.status === 204) {
62	    return undefined as T;
63	  }
64	
65	  const data = await res
66	    .json()
67	    .catch(() => ({ error: 'parse_error', detail: 'unexpected response format' }));
68	
69	  if (!res.ok) {
70	    if (res.status === 401) {
71	      // Notify auth context so it can clear state and redirect to login.
72	      _onUnauthorized?.();
73	    }
74	    throw new HttpError(res.status, data as ApiErrorBody);
75	  }
76	
77	  return data as T;
78	}
79	
80	export const apiClient = {
81	  get: <T>(path: string): Promise<T> => request<T>('GET', path),
82	  post: <T>(path: string, body?: unknown): Promise<T> => request<T>('POST', path, body),
83	};
84	

