	var f HoldingFilter
	if s := c.QueryParam("search"); s != "" {
		f.Search = &s
	}
	if s := c.QueryParam("category"); s != "" {
		f.Category = &s
	}
	if s := c.QueryParam("isbn"); s != "" {
		f.ISBN = &s
	}
	if s := c.QueryParam("active"); s != "" {
		b := s == "true" || s == "1"
		f.Active = &b
	}

	p := parsePagination(c)
	result, err := h.service.ListHoldings(ctx, branchID, f, p)
	if err != nil {
		return err
	}
	return c.JSON(http.StatusOK, result)
